# Floyd算法（全源最短路径，动态规划）
def floyd(graph):
    n = len(graph)
    # 初始化：直接使用输入的邻接矩阵
    dist = [[graph[i][j] for j in range(n)] for i in range(n)]

    # k作为中间点，必须在最外层循环
    for k in range(n):
        for i in range(n):
            for j in range(n):
                if dist[i][k] + dist[k][j] < dist[i][j]:
                    dist[i][j] = dist[i][k] + dist[k][j]

    # 检测负权环
    for i in range(n):
        if dist[i][i] < 0:
            raise ValueError("图中存在负权环")
    return dist

# 邻接矩阵，INF表示不可达
INF = float('inf')
graph = [
    [0, 5, INF, 10],
    [INF, 0, 3, INF],
    [INF, INF, 0, 1],
    [INF, INF, INF, 0]
]
result = floyd(graph)
for row in result:
    print(row)
